using BgCommon.Script.Runtime;namespace BgCommon.Script.Runtime.DotNet;/// <summary>/// 表示 .NET SDK 的版本信息类./// </summary>public class DotNetSdkVersion{    /// <summary>    /// Initializes a new instance of the <see cref="DotNetSdkVersion"/> class.    /// </summary>    /// <param name="version">语义化版本对象.</param>    public DotNetSdkVersion(SemanticVersion version)    {        // 验证传入的版本对象是否为空        ArgumentNullException.ThrowIfNull(version, nameof(version));        // 初始化版本属性        this.Version = version;    }    /// <summary>    /// Gets 具体的 SDK 版本信息.    /// </summary>    public SemanticVersion Version { get; }    /// <summary>    /// 返回表示当前对象的字符串.    /// </summary>    /// <returns>版本的字符串表示形式.</returns>    public override string ToString()    {        // 返回内部版本对象的字符串表示        return this.Version.ToString();    }}